125→        x1={info.p1.x} y1={info.p1.y}
126→        x2={info.p3.x} y2={info.p3.y}
127→        stroke="var(--color-wall-fill)"
128→        strokeWidth={1}
129→        vectorEffect="non-scaling-stroke"
130→      />
131→      {/* Diagonal X: p2→p4 */}
132→      <line
133→        x1={info.p2.x} y1={info.p2.y}
134→        x2={info.p4.x} y2={info.p4.y}
135→        stroke="var(--color-wall-fill)"
136→        strokeWidth={1}
137→        vectorEffect="non-scaling-stroke"
138→      />
139→    </>
140→  );
141→}
