33→export function getViewportRotationHandle(viewport, handleSize) {
34→  const cx = viewport.x + viewport.width / 2;
35→  const stemLength = handleSize * 2.5;
36→  const radius = handleSize / 2;
37→  const stemY1 = viewport.y;
38→  const stemY2 = viewport.y - stemLength;
39→  const cy = stemY2 - radius;
40→  return { cx, cy, radius, stemX: cx, stemY1, stemY2 };
41→}
