221→export function buildPreviewObjectRoot(sceneDescriptor, materialPalette) {
222→  const root = new THREE.Group();
223→  root.name = 'preview-root';
224→
225→  for (const floor of sceneDescriptor.floors) {
226→    const floorGroup = new THREE.Group();
227→    floorGroup.name = `floor-${floor.floorId}`;
228→    floorGroup.visible = floor.visible;
229→    floorGroup.userData = {
230→      floorId: floor.floorId,
231→      floorName: floor.name,
232→      elevation: floor.elevation,
233→    };
234→
235→    for (const descriptor of floor.objects) {
236→      const object = createObjectForDescriptor(descriptor, materialPalette);
237→      object.name = descriptor.id;
238→      object.userData = {
239→        id: descriptor.id,
240→        kind: descriptor.kind,
241→        metadata: descriptor.metadata,
242→      };
243→      floorGroup.add(object);
244→    }
245→
246→    root.add(floorGroup);
247→  }
248→
249→  return root;
250→}
