15→export function rotate(point, center, angleDeg) {
16→  const rad = (angleDeg * Math.PI) / 180;
17→  const cos = Math.cos(rad);
18→  const sin = Math.sin(rad);
19→  const dx = point.x - center.x;
20→  const dy = point.y - center.y;
21→  return {
22→    x: center.x + dx * cos - dy * sin,
23→    y: center.y + dx * sin + dy * cos,
24→  };
25→}
