196→export function snapWallEndpoint(modelPos, {
197→  walls = [],
198→  columns = [],
199→  snapDist,
200→  chainStart = null,
201→  otherPoint = null,
202→  ignoreWallId = null,
203→} = {}) {
204→  let best = null;
205→  const directionHint = otherPoint && distance(otherPoint, modelPos) > EPSILON
206→    ? normalize(subtract(modelPos, otherPoint))
207→    : null;
208→
209→  const consider = (point, priority, attachment = null) => {
210→    const candidateDistance = distance(modelPos, point);
211→    if (candidateDistance > snapDist) return;
212→    best = setBestCandidate(best, {
213→      point: { x: point.x, y: point.y },
214→      attachment: cloneAttachment(attachment),
215→      priority,
216→      distance: candidateDistance,
217→    });
218→  };
219→
220→  if (chainStart) {
221→    consider(chainStart, 0, null);
222→  }
223→
224→  for (const wall of walls) {
225→    if (wall.id === ignoreWallId) continue;
226→    consider(wall.start, 1, null);
227→    consider(wall.end, 1, null);
228→  }
229→
230→  for (const column of columns) {
231→    const corners = columnOutline(column);
232→    corners.forEach((corner, index) => {
233→      consider(corner, 2, {
234→        kind: 'column',
235→        columnId: column.id,
236→        featureType: 'corner',
237→        featureIndex: index,
238→      });
239→    });
240→
241→    for (const face of columnFaces(column)) {
242→      consider(face.midpoint, 3, buildFaceAttachment(column, face, face.midpoint));
243→    }
244→
245→    if (directionHint) {
246→      for (const centerline of columnCenterlines(column)) {
247→        if (Math.abs(dot(directionHint, centerline.axis)) < CENTERLINE_ALIGNMENT_THRESHOLD) continue;
248→        const center = columnCenter(column);
249→        const projection = dot(subtract(modelPos, center), centerline.axis);
250→        if (Math.abs(projection) > centerline.halfLength + snapDist) continue;
251→        const point = add(center, scale(centerline.axis, projection));
252→        consider(point, 4, buildCenterlineAttachment(column, centerline, point));
253→      }
254→    }
255→
256→    for (const face of columnFaces(column)) {
257→      const { point } = nearestPointOnSegment(modelPos, face.start, face.end);
258→      consider(point, 5, buildFaceAttachment(column, face, point));
259→    }
260→  }
261→
262→  for (const wall of walls) {
263→    if (wall.id === ignoreWallId) continue;
264→    const { point, t } = nearestPointOnSegment(modelPos, wall.start, wall.end);
265→    if (t <= 0.001 || t >= 0.999) continue;
266→    consider(point, 6, null);
267→  }
268→
269→  if (!best) return null;
270→  return {
271→    point: best.point,
272→    attachment: best.attachment,
273→  };
274→}
275→
276→export function resolveWallEndpoint(wall, endpointKey, columns = []) {
277→  const syncedWall = syncWallAttachmentPoints(wall, columns);
278→  return { ...syncedWall[endpointKey] };
279→}
280→
281→export function resolveWallEndpoints(wall, columns = []) {
282→  const syncedWall = syncWallAttachmentPoints(wall, columns);
283→  return {
284→    start: { ...syncedWall.start },
285→    end: { ...syncedWall.end },
286→    startAttachment: cloneAttachment(syncedWall.startAttachment),
287→    endAttachment: cloneAttachment(syncedWall.endAttachment),
288→  };
289→}
290→
291→export function resolveCenterlineAxis(column, featureIndex) {
292→  const { xAxis, yAxis } = columnAxes(column);
293→  return featureIndex === 1 ? yAxis : xAxis;
294→}
