 15→function hitTest(modelPos, floor, annotationTolerance) {
 16→  // Hit test doors first (smaller targets, higher priority)
 17→  for (const door of floor.doors) {
 18→    const wall = floor.walls.find(w => w.id === door.wallId);
 19→    if (!wall) continue;
 20→    const info = doorOutlineOnWall(wall, door);
 21→    const poly = [info.p1, info.p2, info.p3, info.p4];
 22→    if (pointInPolygon(modelPos, poly)) {
 23→      return { id: door.id, type: 'door' };
 24→    }
 25→  }
 26→
 27→  // Hit test windows
 28→  for (const win of floor.windows) {
 29→    const wall = floor.walls.find(w => w.id === win.wallId);
 30→    if (!wall) continue;
 31→    const info = windowOutlineOnWall(wall, win);
 32→    const poly = [info.p1, info.p2, info.p3, info.p4];
 33→    if (pointInPolygon(modelPos, poly)) {
 34→      return { id: win.id, type: 'window' };
 35→    }
 36→  }
 37→
 38→  // Hit test walls
 39→  // Hit test columns
 40→  for (const sc of (floor.sectionCuts || [])) {
 41→    if (hitTestSectionCut(modelPos, sc, annotationTolerance)) {
 42→      return { id: sc.id, type: 'sectionCut' };
 43→    }
 44→  }
 45→
 46→  for (const column of (floor.columns || [])) {
 47→    const outline = columnOutline(column);
 48→    if (pointInPolygon(modelPos, outline)) {
 49→      return { id: column.id, type: 'column' };
 50→    }
 51→  }
 52→
 53→  // Hit test beams
 54→  for (const beam of (floor.beams || [])) {
 55→    const renderData = getBeamRenderData(beam, floor.columns || []);
 56→    if (!renderData) continue;
 57→    if (pointInPolygon(modelPos, renderData.outline)) {
 58→      return { id: beam.id, type: 'beam' };
 59→    }
 60→  }
 61→
 62→  // Hit test walls
 63→  for (const wall of floor.walls) {
 64→    const outline = getWallRenderData(wall, floor.columns || []).outline;
 65→    if (pointInPolygon(modelPos, outline)) {
 66→      return { id: wall.id, type: 'wall' };
 67→    }
 68→  }
 69→
 70→  // Hit test stairs after walls/beams/columns so current editing priority stays intact.
 71→  for (const stair of (floor.stairs || [])) {
 72→    const renderData = getStairRenderData(stair);
 73→    if (!renderData) continue;
 74→    if (pointInPolygon(modelPos, renderData.outline)) {
 75→      return { id: stair.id, type: 'stair' };
 76→    }
 77→  }
 78→
 79→  // Hit test rooms (lowest priority)
 80→  for (const room of floor.rooms) {
 81→    if (room.points?.length >= 3 && pointInPolygon(modelPos, room.points)) {
 82→      return { id: room.id, type: 'room' };
 83→    }
 84→  }
 85→
 86→  for (const slab of (floor.slabs || [])) {
 87→    if (slabContainsPoint(slab, modelPos)) {
 88→      return { id: slab.id, type: 'slab' };
 89→    }
 90→  }
 91→
 92→  const annotationHit = hitTestAnnotation(modelPos, floor, annotationTolerance);
 93→  if (annotationHit) {
 94→    return annotationHit;
 95→  }
 96→
 97→  return null;
 98→}
