 49→    if (!floor.rooms) floor.rooms = [];
 50→    for (const room of floor.rooms) {
 51→      if (!room.points) room.points = [];
 52→      if (room.area === undefined) room.area = 0;
 53→    }
 54→  });
 55→
 56→  // Backfill door/window type fields for old saves
 57→  for (const floor of project.floors) {
 58→    if (!floor.doors) floor.doors = [];
 59→    for (const door of floor.doors) {
 60→      if (!door.type) door.type = 'swing';
