182→
183→export function createRoom(name = 'Room', points = [], color = ROOM_COLOR) {
184→  const area = polygonArea(points);
185→  const centroid = points.length >= 3 ? polygonCentroid(points) : { x: 0, y: 0 };
186→  return {
187→    id: generateId('room'),
188→    name,
189→    points: points.map(p => ({ x: p.x, y: p.y })),
190→    labelPosition: { ...centroid },
191→    color,
192→    area,
193→  };
194→}
