364→    case 'ANNOTATION_UPDATE':
365→      return updateFloor(state, action.floorId, f => ({
366→        ...f,
367→        annotations: (f.annotations || []).map((annotation) => (
368→          annotation.id === action.annotation.id ? { ...annotation, ...action.annotation } : annotation
