391→      }));
392→
393→    case 'SLAB_UPDATE':
394→      return updateFloor(state, action.floorId, f => ({
395→        ...f,
396→        slabs: (f.slabs || []).map(s =>
397→          s.id === action.slab.id ? { ...s, ...action.slab } : s
398→        ),
399→      }));
400→
401→    case 'SLAB_DELETE':
402→      return updateFloor(state, action.floorId, f => ({
