405→      }));
406→
407→    case 'SECTION_ADD':
408→      return updateFloor(state, action.floorId, f => ({
409→        ...f,
410→        sectionCuts: [...(f.sectionCuts || []), action.sectionCut],
411→      }));
412→
413→    case 'SECTION_UPDATE':
414→      return updateFloor(state, action.floorId, f => ({
415→        ...f,
416→        sectionCuts: (f.sectionCuts || []).map(s =>
417→          s.id === action.sectionCut.id ? { ...s, ...action.sectionCut } : s
418→        ),
419→      }));
420→
421→    case 'SECTION_DELETE':
