425→      }));
426→
427→    case 'ROOM_ADD':
428→      return updateFloor(state, action.floorId, f => ({
429→        ...f,
430→        rooms: [...f.rooms, action.room],
431→      }));
432→
433→    case 'ROOM_UPDATE':
434→      return updateFloor(state, action.floorId, f => ({
435→        ...f,
436→        rooms: f.rooms.map(r => r.id === action.room.id ? { ...r, ...action.room } : r),
437→      }));
438→
439→    case 'ROOM_DELETE':
440→      return updateFloor(state, action.floorId, f => ({
441→        ...f,
442→        rooms: f.rooms.filter(r => r.id !== action.roomId),
443→      }));
444→
445→    case 'ROOMS_SET':
446→      return updateFloor(state, action.floorId, f => ({
447→        ...f,
448→        rooms: action.rooms,
449→      }));
450→
451→    case 'FLOOR_REPLACE':
452→      return updateFloor(state, action.floorId, () => ({
453→        ...action.floor,
454→      }), true, { sort: true });
455→
456→    case 'COLUMN_ADD':
457→      return updateFloor(state, action.floorId, f => ({
458→        ...f, columns: [...(f.columns || []), action.column],
459→      }));
460→    case 'COLUMN_DUPLICATE':
461→      return updateFloor(state, action.floorId, f => ({
462→        ...f,
463→        columns: [...(f.columns || []), action.column],
464→      }));
465→    case 'COLUMN_UPDATE':
466→      return updateFloor(state, action.floorId, f => {
467→        const nextColumns = (f.columns || []).map(c => (
468→          c.id === action.column.id ? { ...c, ...action.column } : c
469→        ));
470→        return {
471→          ...f,
472→          columns: nextColumns,
473→          walls: f.walls.map(w => syncWallAttachmentPoints(w, nextColumns)),
474→        };
475→      });
476→    case 'COLUMN_DELETE':
477→      return updateFloor(state, action.floorId, f => ({
478→        ...f,
479→        columns: (f.columns || []).filter(c => c.id !== action.columnId),
480→        walls: f.walls.map(w => detachColumnAttachments(w, f.columns || [], action.columnId)),
481→        beams: (f.beams || []).filter(beam => (
482→          beam.startRef?.id !== action.columnId && beam.endRef?.id !== action.columnId
483→        )),
484→      }));
485→
486→    case 'MARK_SAVED':
487→      return {
488→        ...state,
489→        isDirty: false,
490→        lastSavedAt: new Date().toISOString(),
491→        savedSnapshot: snapshotProject(state.project),
492→      };
493→
494→    case 'UNDO': {
495→      if (state.history.length === 0) return state;
496→      const previousProject = state.history[state.history.length - 1];
497→      return {
498→        ...state,
499→        project: previousProject,
500→        history: state.history.slice(0, -1),
501→        future: [state.project, ...state.future].slice(0, HISTORY_LIMIT),
502→        isDirty: snapshotProject(previousProject) !== state.savedSnapshot,
503→      };
504→    }
505→
506→    case 'REDO': {
507→      if (state.future.length === 0) return state;
508→      const nextProject = state.future[0];
509→      return {
510→        ...state,
511→        project: nextProject,
512→        history: [...state.history, state.project].slice(-HISTORY_LIMIT),
513→        future: state.future.slice(1),
514→        isDirty: snapshotProject(nextProject) !== state.savedSnapshot,
515→      };
516→    }
517→
518→    default:
519→      return state;
520→  }
521→}
