534→export function ProjectProvider({ children }) {
535→  const [state, dispatch] = useReducer(projectReducer, initialState);
536→  return (
537→    <ProjectContext.Provider value={{ state, dispatch }}>
538→      {children}
539→    </ProjectContext.Provider>
540→  );
541→}
