543→export function useProject() {
544→  const ctx = useContext(ProjectContext);
545→  if (!ctx) throw new Error('useProject must be used within ProjectProvider');
546→  const { state, dispatch } = ctx;
547→
548→  const duplicateFloor = (floorId) => {
549→    const floor = state.project.floors.find((entry) => entry.id === floorId) || null;
550→    return floor ? createDuplicatedFloor(floor) : null;
551→  };
552→
553→  return {
554→    project: state.project,
555→    isDirty: state.isDirty,
556→    lastSavedAt: state.lastSavedAt,
557→    canUndo: state.history.length > 0,
558→    canRedo: state.future.length > 0,
559→    dispatch,
560→    duplicateFloor,
561→    getFloor: (floorId) => state.project.floors.find(f => f.id === floorId),
562→  };
563→}
