 93→    if (e.button === 1 || (e.button === 0 && spaceHeld.current)) {
 94→      isPanning.current = true;
 95→      lastPanPos.current = { x: e.clientX, y: e.clientY };
 96→      e.preventDefault();
 97→      return;
 98→    }
 99→
100→    const modelPos = getModelPos(e);
101→    if (pastePreview?.active && e.button === 0) {
102→      placePaste(modelPos);
103→      return;
104→    }
105→    tool.onMouseDown(modelPos, e);
106→  }, [getModelPos, pastePreview, placePaste, tool]);
107→
108→  const handleMouseMove = useCallback((e) => {
109→    if (isPanning.current) {
110→      const dx = e.clientX - lastPanPos.current.x;
111→      const dy = e.clientY - lastPanPos.current.y;
112→      editorDispatch({ type: 'PAN', dx, dy });
113→      lastPanPos.current = { x: e.clientX, y: e.clientY };
114→      return;
115→    }
116→
117→    const modelPos = getModelPos(e);
118→    cursorPosRef.current = modelPos;
119→    setCursorPos(modelPos);
120→    if (pastePreview?.active) {
121→      updatePastePreview(modelPos);
122→      return;
123→    }
124→    tool.onMouseMove(modelPos, e);
125→  }, [getModelPos, pastePreview, tool, updatePastePreview, editorDispatch]);
126→
127→  const handleMouseUp = useCallback((e) => {
128→    if (isPanning.current) {
129→      isPanning.current = false;
130→      return;
131→    }
132→    if (pastePreview?.active) return;
133→    const modelPos = getModelPos(e);
134→    tool.onMouseUp(modelPos, e);
135→  }, [getModelPos, pastePreview, tool]);
136→
137→  const handleDoubleClick = useCallback((e) => {
138→    if (pastePreview?.active) return;
139→    const modelPos = getModelPos(e);
140→    tool.onDoubleClick(modelPos, e);
141→  }, [getModelPos, pastePreview, tool]);
142→
143→  const handleWheel = useCallback((e) => {
144→    e.preventDefault();
145→    const rect = svgRef.current.getBoundingClientRect();
146→    const mouseX = e.clientX - rect.left;
147→    const mouseY = e.clientY - rect.top;
148→
149→    const direction = e.deltaY < 0 ? 1 : -1;
150→    const factor = direction > 0 ? ZOOM_FACTOR : 1 / ZOOM_FACTOR;
151→    const newZoom = Math.max(MIN_ZOOM, Math.min(MAX_ZOOM, viewport.zoom * factor));
152→
153→    // Zoom centered on cursor
154→    const newPanX = mouseX - (mouseX - viewport.panX) * (newZoom / viewport.zoom);
155→    const newPanY = mouseY - (mouseY - viewport.panY) * (newZoom / viewport.zoom);
156→
157→    editorDispatch({ type: 'ZOOM', zoom: newZoom, panX: newPanX, panY: newPanY });
158→  }, [viewport, editorDispatch]);
159→
160→  useEffect(() => {
161→    if (!statusMessage) return undefined;
162→
163→    const timer = window.setTimeout(() => {
164→      editorDispatch({ type: 'CLEAR_STATUS_MESSAGE' });
165→    }, 2500);
166→
167→    return () => window.clearTimeout(timer);
168→  }, [statusMessage, editorDispatch]);
169→
170→  useEffect(() => {
171→    const handleKeyDown = (e) => {
172→      if (isTypingTarget(e.target)) return;
173→
174→      if (e.key === ' ') {
175→        spaceHeld.current = true;
176→        e.preventDefault();
177→      }
178→
179→      if ((e.ctrlKey || e.metaKey) && viewMode === 'plan') {
180→        const key = e.key.toLowerCase();
181→        if (key === 'c') {
182→          e.preventDefault();
183→          copySelection();
184→          return;
185→        }
186→        if (key === 'x') {
187→          e.preventDefault();
188→          cutSelection();
189→          return;
190→        }
191→        if (key === 'v') {
192→          e.preventDefault();
193→          beginPaste(cursorPosRef.current);
194→          return;
195→        }
196→      }
197→
198→      if (e.key === 'Escape' && pastePreview?.active) {
199→        e.preventDefault();
200→        cancelPaste();
201→        return;
202→      }
203→
204→      // Tool shortcuts
205→      if (viewMode === 'plan' && !e.ctrlKey && !e.metaKey) {
206→        switch (e.key.toLowerCase()) {
207→          case 'v':
208→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.SELECT });
209→            return;
210→          case 'm':
211→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.DIMENSION });
212→            return;
213→          case 'w':
214→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.WALL });
215→            return;
216→          case 'b':
217→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.BEAM });
218→            return;
219→          case 't':
220→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.STAIR });
221→            return;
222→          case 'q':
223→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.SECTION });
224→            return;
225→          case 's':
226→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.SLAB });
227→            return;
228→          case 'r':
229→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.ROOM });
230→            return;
231→          case 'd':
232→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.DOOR });
233→            return;
234→          case 'n':
235→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.WINDOW });
236→            return;
237→          case 'c':
238→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.COLUMN });
239→            return;
240→        }
241→      }
242→
243→      tool.onKeyDown(e);
244→    };
245→
246→    const handleKeyUp = (e) => {
247→      if (isTypingTarget(e.target)) return;
248→
249→      if (e.key === ' ') {
250→        spaceHeld.current = false;
251→      }
252→    };
253→
254→    window.addEventListener('keydown', handleKeyDown);
255→    window.addEventListener('keyup', handleKeyUp);
256→    return () => {
257→      window.removeEventListener('keydown', handleKeyDown);
258→      window.removeEventListener('keyup', handleKeyUp);
259→    };
260→  }, [beginPaste, cancelPaste, copySelection, cutSelection, pastePreview?.active, tool, editorDispatch, viewMode]);
261→
262→  // Prevent default context menu on SVG
263→  useEffect(() => {
264→    const svg = svgRef.current;
265→    if (!svg) return;
266→    const prevent = (e) => e.preventDefault();
267→    svg.addEventListener('contextmenu', prevent);
268→    svg.addEventListener('wheel', handleWheel, { passive: false });
269→    return () => {
270→      svg.removeEventListener('contextmenu', prevent);
271→      svg.removeEventListener('wheel', handleWheel);
272→    };
273→  }, [handleWheel]);
274→
275→  const cursor = spaceHeld.current ? 'grab' : pastePreview?.active ? 'copy' : tool.getCursor();
276→  const zoomPercent = Math.round(viewport.zoom * 1000);
277→  const displayedTool = viewMode.startsWith('elevation_') ? 'select' : activeTool;
278→  const marqueeBounds = toolState.dragType === 'marquee' && toolState.startPos && toolState.currentPos
279→    ? normalizeRectBounds(toolState.startPos, toolState.currentPos)
280→    : null;
281→  const selectionCount = regionSelection?.objectCount || 0;
282→
283→  return (
284→    <div className={styles.canvasContainer}>
285→      <svg
286→        ref={svgRef}
287→        className={styles.svg}
288→        style={{ cursor }}
289→        onMouseDown={handleMouseDown}
290→        onMouseMove={handleMouseMove}
291→        onMouseUp={handleMouseUp}
292→        onDoubleClick={handleDoubleClick}
293→      >
294→        <g transform={`translate(${viewport.panX}, ${viewport.panY}) scale(${viewport.zoom})`}>
295→          {viewMode === 'plan' && showGrid && <GridRenderer />}
296→          {viewMode === 'plan' && showGrid && (
297→            <rect
298→              x={-100000} y={-100000}
299→              width={200000} height={200000}
300→              fill="url(#grid-major)"
301→              style={{ pointerEvents: 'none' }}
302→            />
303→          )}
304→          {floor && (
305→            viewMode === 'plan' ? (
306→              <>
307→                {(floor.slabs || []).map(slab => (
308→                  <SlabRenderer key={slab.id} slab={slab} selectedId={selectedId} />
309→                ))}
310→                <RoomRenderer rooms={floor.rooms} selectedId={selectedId} />
311→                <RoomPreview toolState={toolState} activeTool={activeTool} />
312→                <WallRenderer walls={floor.walls} columns={floor.columns || []} />
313→                <BeamRenderer beams={floor.beams || []} columns={floor.columns || []} />
314→                <StairRenderer stairs={floor.stairs || []} />
315→                <ColumnRenderer columns={floor.columns || []} />
316→                <DoorRenderer doors={floor.doors} walls={floor.walls} />
317→                <WindowRenderer windows={floor.windows} walls={floor.walls} />
318→                {(floor.sectionCuts || []).map(sc => (
319→                  <SectionCutRenderer key={sc.id} sectionCut={sc} selectedId={selectedId} />
320→                ))}
321→                <AnnotationRenderer floor={floor} />
322→                <ClipboardPreviewLayer content={previewContent} />
323→                <RegionSelectionOverlay
324→                  marqueeBounds={marqueeBounds}
325→                  selectionBounds={regionSelection?.bounds || null}
326→                />
327→                <SelectionOverlay
328→                  selectedId={selectedId}
329→                  selectedType={selectedType}
330→                  floor={floor}
331→                  zoom={viewport.zoom}
332→                />
333→                <DimensionPreview toolState={toolState} activeTool={activeTool} />
334→                <WallPreview toolState={toolState} activeTool={activeTool} />
335→                <SlabPreview toolState={toolState} activeTool={activeTool} />
336→                <BeamPreview
337→                  toolState={toolState}
338→                  activeTool={activeTool}
339→                  columns={floor.columns || []}
340→                  floorLevel={getFloorElevation(floor)}
341→                />
342→                <StairPreview
343→                  toolState={toolState}
344→                  activeTool={activeTool}
345→                  floorId={floor.id}
346→                />
347→                <DoorWindowPreview
348→                  toolState={toolState}
349→                  activeTool={activeTool}
350→                  walls={floor.walls}
351→                />
352→                <SectionCutPreview toolState={toolState} activeTool={activeTool} />
353→                <ColumnPreview toolState={toolState} activeTool={activeTool} />
354→              </>
355→            ) : viewMode === 'section_view' ? (
356→              <SectionRenderer floor={floor} activeSectionCutId={activeSectionCutId} />
357→            ) : (
358→              <ElevationRenderer
359→                floor={floor}
360→                viewMode={viewMode}
361→                selectedId={selectedId}
362→                selectedType={selectedType}
363→              />
364→            )
365→          )}
366→        </g>
367→      </svg>
368→      <div className={styles.statusBar}>
369→        <span>X: {Math.round(cursorPos.x)} mm</span>
370→        <span>Y: {Math.round(cursorPos.y)} mm</span>
371→        <span>Zoom: {zoomPercent}%</span>
372→        <span>View: {viewMode}</span>
373→        <span>Tool: {displayedTool}</span>
374→        {selectionCount > 0 && <span>Selection: {selectionCount} objects</span>}
375→        {pastePreview?.active && <span>Paste: click to place</span>}
376→        {statusMessage && <span className={styles.statusMessage}>{statusMessage}</span>}
377→      </div>
378→    </div>
379→  );
380→}
