 1→import { STAIR_RISERS, STAIR_RISER_HEIGHT, STAIR_TREAD_DEPTH, STAIR_WIDTH } from '@/domain/defaults';
 2→import { TOOLS } from '@/editor/tools';
 3→import { getStairRenderData } from '@/geometry/stairGeometry';
 4→
 5→export default function StairPreview({ toolState, activeTool, floorId }) {
 6→  if (activeTool !== TOOLS.STAIR) return null;
 7→  if (!toolState.stairStartPoint || toolState.stairPreviewAngle == null) return null;
 8→
 9→  const previewStair = {
10→    id: 'stair_preview',
11→    startPoint: toolState.stairStartPoint,
12→    width: STAIR_WIDTH,
13→    numberOfRisers: STAIR_RISERS,
14→    riserHeight: STAIR_RISER_HEIGHT,
15→    treadDepth: STAIR_TREAD_DEPTH,
16→    direction: { angle: toolState.stairPreviewAngle },
17→    floorRelation: { fromFloorId: floorId, toFloorId: floorId },
18→  };
19→
20→  const renderData = getStairRenderData(previewStair);
21→  if (!renderData) return null;
22→
23→  const points = renderData.outline.map((point) => `${point.x},${point.y}`).join(' ');
24→
25→  return (
26→    <g style={{ pointerEvents: 'none' }}>
27→      <polygon
28→        points={points}
29→        fill="rgba(207, 179, 120, 0.1)"
30→        stroke="var(--color-selection)"
31→        strokeWidth={2}
32→        strokeDasharray="6 3"
33→        vectorEffect="non-scaling-stroke"
34→      />
35→      {renderData.treads.map((tread, index) => (
36→        <line
37→          key={`preview-tread-${index}`}
38→          x1={tread.start.x}
39→          y1={tread.start.y}
40→          x2={tread.end.x}
41→          y2={tread.end.y}
42→          stroke="var(--color-selection)"
43→          strokeWidth={1.2}
44→          vectorEffect="non-scaling-stroke"
45→        />
46→      ))}
47→      {renderData.arrow && (
48→        <>
49→          <line
50→            x1={renderData.arrow.start.x}
51→            y1={renderData.arrow.start.y}
52→            x2={renderData.arrow.end.x}
53→            y2={renderData.arrow.end.y}
54→            stroke="var(--color-selection)"
55→            strokeWidth={1.6}
56→            vectorEffect="non-scaling-stroke"
57→          />
58→          <line
59→            x1={renderData.arrow.end.x}
60→            y1={renderData.arrow.end.y}
61→            x2={renderData.arrow.headA.x}
62→            y2={renderData.arrow.headA.y}
63→            stroke="var(--color-selection)"
64→            strokeWidth={1.6}
65→            vectorEffect="non-scaling-stroke"
66→          />
67→          <line
68→            x1={renderData.arrow.end.x}
69→            y1={renderData.arrow.end.y}
70→            x2={renderData.arrow.headB.x}
71→            y2={renderData.arrow.headB.y}
72→            stroke="var(--color-selection)"
73→            strokeWidth={1.6}
74→            vectorEffect="non-scaling-stroke"
75→          />
76→        </>
77→      )}
78→    </g>
79→  );
80→}
